| MCP:y9W8X9 | public class SecurityChain {
| MCP:y9W8X9 |     private final AuthenticationFilter jwtAuthFilter;
| MCP:y9W8X9 |     private final AuthenticationProvider authenticationProvider;
| MCP:y9W8X9 |     private final LogoutHandler logoutHandler;
| MCP:y9W8X9 |     private final AuthenticationEntryPoint jwtAuthEntryPoint;
| MCP:y9W8X9 | 
| MCP:y9W8X9 |     /**
| MCP:y9W8X9 |      * Defines the bean used to manage authentication
| MCP:y9W8X9 |      * @param http HttpSecurity
| MCP:y9W8X9 |      * @return SecurityFilterChain
| MCP:y9W8X9 |      * @throws Exception if the authentication manager cannot be created
| MCP:y9W8X9 |      */
| MCP:y9W8X9 |     @Bean
| MCP:y9W8X9 |     public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
| MCP:y9W8X9 |         http
| MCP:y9W8X9 |             .csrf(csrf -> csrf.disable())
| MCP:y9W8X9 |             .authorizeHttpRequests(auth -> auth
| MCP:y9W8X9 |                 .requestMatchers(
| MCP:y9W8X9 |                     "/auth/**",
| MCP:y9W8X9 |                     "/v3/api-docs/**",
| MCP:y9W8X9 |                     "/swagger-resources",
| MCP:y9W8X9 |                     "/swagger-resources/**",
| MCP:y9W8X9 |                     "/configuration/ui",
| MCP:y9W8X9 |                     "/configuration/security",
| MCP:y9W8X9 |                     "/swagger-ui/**",
| MCP:y9W8X9 |                     "/webjars/**",
| MCP:y9W8X9 |                     "/swagger-ui.html",
| MCP:y9W8X9 |                     "/actuator/**"
| MCP:y9W8X9 |                 ).permitAll()
| MCP:y9W8X9 |                 .requestMatchers("/management/**").hasAnyRole(ADMIN.name(), MANAGER.name())
| MCP:y9W8X9 |                 .requestMatchers(GET, "/management/**").hasAnyAuthority(ADMIN_READ.name(), MANAGER_READ.name())
| MCP:y9W8X9 |                 .requestMatchers(POST, "/management/**").hasAnyAuthority(ADMIN_CREATE.name(), MANAGER_CREATE.name())
| MCP:y9W8X9 |                 .requestMatchers(PUT, "/management/**").hasAnyAuthority(ADMIN_UPDATE.name(), MANAGER_UPDATE.name())
| MCP:y9W8X9 |                 .requestMatchers(PATCH, "/management/**").hasAnyAuthority(ADMIN_UPDATE.name(), MANAGER_UPDATE.name())
| MCP:y9W8X9 |                 .requestMatchers(DELETE, "/management/**").hasAnyAuthority(ADMIN_DELETE.name(), MANAGER_DELETE.name())
| MCP:y9W8X9 |                 .anyRequest().authenticated()
| MCP:y9W8X9 |             )
| MCP:y9W8X9 |             .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
| MCP:y9W8X9 |             .authenticationProvider(authenticationProvider)
| MCP:y9W8X9 |             .addFilterBefore(jwtAuthFilter, UsernamePasswordAuthenticationFilter.class)
| MCP:y9W8X9 |             .logout(logout -> logout
| MCP:y9W8X9 |                 .logoutUrl("/auth/logout")
| MCP:y9W8X9 |                 .addLogoutHandler(logoutHandler)
| MCP:y9W8X9 |                 .logoutSuccessHandler((request, response, authentication) -> SecurityContextHolder.clearContext())
| MCP:y9W8X9 |             )
| MCP:y9W8X9 |             .exceptionHandling(exception -> exception.authenticationEntryPoint(jwtAuthEntryPoint));
| MCP:y9W8X9 |         return http.build();
| MCP:y9W8X9 |     }
| MCP:y9W8X9 | }

