| MCP:y9W8X9 | import org.springframework.stereotype.Component;
| MCP:y9W8X9 | import org.springframework.web.filter.OncePerRequestFilter;
| MCP:y9W8X9 | 
| MCP:y9W8X9 | import java.io.IOException;
| MCP:y9W8X9 | 
| MCP:y9W8X9 | /**
| MCP:y9W8X9 |  * JWT Authentication Filter class for authenticating JWT tokens
| MCP:y9W8X9 |  * and setting the authentication in the Security Context
| MCP:y9W8X9 |  * @see OncePerRequestFilter
| MCP:y9W8X9 |  * @see JwtService
| MCP:y9W8X9 |  * @see UserDetailsService
| MCP:y9W8X9 |  * @see TokenRepository
| MCP:y9W8X9 |  * @author tzesh
| MCP:y9W8X9 |  */
| MCP:y9W8X9 | @Component
| MCP:y9W8X9 | @RequiredArgsConstructor
| MCP:y9W8X9 | public class AuthenticationFilter extends OncePerRequestFilter {
| MCP:y9W8X9 | 
| MCP:y9W8X9 |     private final JwtService jwtService;
| MCP:y9W8X9 |     private final UserDetailsService userDetailsService;
| MCP:y9W8X9 |     private final TokenRepository tokenRepository;
| MCP:y9W8X9 | 
| MCP:y9W8X9 |     /**
| MCP:y9W8X9 |      * Method that filters the requests and authenticates the user
| MCP:y9W8X9 |      * @param request request HttpServletRequest
| MCP:y9W8X9 |      * @param response response HttpServletResponse
| MCP:y9W8X9 |      * @param filterChain filterChain that contains the filters
| MCP:y9W8X9 |      * @throws ServletException if the servlet encounters difficulty
| MCP:y9W8X9 |      * @throws IOException if the servlet encounters difficulty
| MCP:y9W8X9 |      */
| MCP:y9W8X9 |     @Override
| MCP:y9W8X9 |     protected void doFilterInternal(
| MCP:y9W8X9 |             @NonNull HttpServletRequest request,
| MCP:y9W8X9 |             @NonNull HttpServletResponse response,
| MCP:y9W8X9 |             @NonNull FilterChain filterChain
| MCP:y9W8X9 |     ) throws ServletException, IOException {
| MCP:y9W8X9 |         // if the request is for authentication, skip the filter
| MCP:y9W8X9 |         if (request.getServletPath().contains("/api/v1/auth")) {
| MCP:y9W8X9 |             filterChain.doFilter(request, response);
| MCP:y9W8X9 |             return;
| MCP:y9W8X9 |         }
| MCP:y9W8X9 | 
| MCP:y9W8X9 |         // get the token from the request header
| MCP:y9W8X9 |         final String authHeader = request.getHeader("Authorization");
| MCP:y9W8X9 | 
| MCP:y9W8X9 |         // initialize the token and username
| MCP:y9W8X9 |         final String jwt;
| MCP:y9W8X9 |         final String username;
| MCP:y9W8X9 | 
| MCP:y9W8X9 |         // if the token is not present or does not start with "Bearer ", skip the filter
| MCP:y9W8X9 |         if (authHeader == null ||!authHeader.startsWith("Bearer ")) {
| MCP:y9W8X9 |             filterChain.doFilter(request, response);
| MCP:y9W8X9 |             return;
| MCP:y9W8X9 |         }
| MCP:y9W8X9 | 
| MCP:y9W8X9 |         // extract the token from the header
| MCP:y9W8X9 |         jwt = authHeader.substring(7);
| MCP:y9W8X9 | 
| MCP:y9W8X9 |         // extract the username from the token
| MCP:y9W8X9 |         username = jwtService.extractUsername(jwt);
| MCP:y9W8X9 | 
| MCP:y9W8X9 |         // if the username is not null and the authentication context is null, authenticate the user
| MCP:y9W8X9 |         if (username != null && SecurityContextHolder.getContext().getAuthentication() == null) {
| MCP:y9W8X9 |             // load the user details from the database
| MCP:y9W8X9 |             UserDetails userDetails = this.userDetailsService.loadUserByUsername(username);
| MCP:y9W8X9 | 
| MCP:y9W8X9 |             // check if the token is valid and not revoked
| MCP:y9W8X9 |             var isTokenValid = tokenRepository.findByToken(jwt)
| MCP:y9W8X9 |                     .map(t -> !t.isExpired() && !t.isRevoked())
| MCP:y9W8X9 |                     .orElse(false);
| MCP:y9W8X9 | 
| MCP:y9W8X9 |             // if the token is valid, set the authentication context
| MCP:y9W8X9 |             if (jwtService.isTokenValid(jwt, userDetails) && isTokenValid) {
| MCP:y9W8X9 |                 // create the authentication token
| MCP:y9W8X9 |                 UsernamePasswordAuthenticationToken authToken = new UsernamePasswordAuthenticationToken(
| MCP:y9W8X9 |                         userDetails,
| MCP:y9W8X9 |                         null,
| MCP:y9W8X9 |                         userDetails.getAuthorities()
| MCP:y9W8X9 |                 );
| MCP:y9W8X9 | 
| MCP:y9W8X9 |                 // set the authentication details
| MCP:y9W8X9 |                 authToken.setDetails(
| MCP:y9W8X9 |                         new WebAuthenticationDetailsSource().buildDetails(request)
| MCP:y9W8X9 |                 );
| MCP:y9W8X9 | 
| MCP:y9W8X9 |                 // set the authentication context
| MCP:y9W8X9 |                 SecurityContextHolder.getContext().setAuthentication(authToken);
| MCP:y9W8X9 |             }
| MCP:y9W8X9 |         }
| MCP:y9W8X9 | 
| MCP:y9W8X9 |         // continue the filter chain
| MCP:y9W8X9 |         filterChain.doFilter(request, response);
| MCP:y9W8X9 |     }
| MCP:y9W8X9 | }

